    from collections import defaultdict
    stats = defaultdict(lambda: [0.0, 0, 0, 0, 0.0, 0])
    # [gs*nm sum, nm sum, n, conflict_n, tone_sum, tone_n]
    for iso3, gs, nm, qc, tone in all_gs_rows:
        s = stats[iso3]
        s[0] += gs * nm
        s[1] += nm
