    mb_data = [{"iso3": r["iso3"], "count": r["n"]} for r in goldstein_data]
    mb_path = MB_DATA_DIR / f"{day_key}.json"
    with open(mb_path, "w", encoding="utf-8") as f:
        json.dump(mb_data, f, separators=(",", ":"))
